import { ImageResponse } from "next/og";

const FONT_B64 = "";

function fontData(): ArrayBuffer {
  const bin = atob(FONT_B64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return bytes.buffer;
}

